insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chiyoda'), 'tokyo-chiyoda-emergency-alert', '千代田区 救急通報システム（高齢者・障害者の緊急通報・見守り）', 'ひとり暮らしの高齢者や障害のある方などの自宅に緊急通報装置を設置し、急病・事故などの緊急時にボタンを押すと受信センターに通報され、現場派遣員の急行や救急車の手配などで安否確認・救助を行う千代田区の事業。公式情報では24時間365日対応で利用料は無料とされています。', 'ひとり暮らしの高齢者や障害のある方の家に緊急通報の機器を取り付け、急に具合が悪くなったときなどにボタンを押すと、受信センターに連絡が行き、スタッフが駆けつけたり救急車を手配したりして助けてくれる、千代田区のサービスです。公式では24時間・年中無休で、利用料は無料と案内されています。', 'service', '公式（千代田区）の確認では、高齢者向けは65歳以上で区内に住所があり、身体上の慢性疾患があるなど日常生活を営むうえで常時注意を要する状態で、ひとり暮らしまたは高齢者のみ世帯（日中または夜間に高齢者のみになる世帯を含む）の方が対象となる可能性があります。あわせて障害者向けの緊急通報システムも公式サイト上にあり、18歳以上で身体障害者手帳1〜2級（内部障害は3級以上）等に該当し、ひとり暮らしまたは障害者・高齢者のみ世帯の方が対象となる可能性があります。対象年齢・要件・障害種別の詳細は公式ページで確認してください。', '公式情報では利用料は無料とされています（機器の貸与・設置）。詳細・最新の取り扱いは公式ページでご確認ください。', '公式ページに申込締切の記載は確認できませんでした。設置（サービス開始）まで約1か月程度かかる旨が案内されています。', '相談センター（3か所）での申請、もしくはオンライン申請に対応していると公式で案内されています。設置（サービス開始）まで約1か月程度かかる旨が記載されています。最新の手続きは公式ページでご確認ください。', '救急通報システム利用申請書兼登録書、および民間賃貸住宅の場合は設置承諾書が必要と公式で案内されています。障害者向けは身体障害者手帳または特定医療費（指定難病）受給者証・印鑑等が案内されています。詳細は公式ページでご確認ください。', TRUE, '千代田区 保健福祉部 在宅支援課 在宅支援係', '03-6265-6482・6486', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/sasaeai/tsuho.html', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/sasaeai/tsuho.html', '救急通報システム - 千代田区', '2026-06-24', 'high', ARRAY['targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本ページは公式情報をもとにした概要です。対象・利用料・機器の種別・申請方法などは変更される場合があるため、最終的な可否は必ず千代田区の公式ページおよび担当窓口でご確認ください。当サイトが申請を代わりに行うすることはありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
