insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-chiyoda-emergency-alert","status":"published","title":"千代田区 救急通報システム（高齢者・障害者の緊急通報・見守り）","officialUrl":"https://www.city.chiyoda.lg.jp/koho/kenko/koresha/sasaeai/tsuho.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-chiyoda-emergency-alert:dG9reW8tY2hpeW9kYS1lbWVyZ2VuY3ktYWxlcnR8' from public.support_programs sp where sp.slug='tokyo-chiyoda-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chuo'), 'tokyo-chuo-emergency-alert', '緊急通報システム（中央区）', '中央区が、ひとり暮らしの高齢者や障害のある方等の自宅に緊急通報機器（本体・緊急ペンダント）や見守りセンサー・火災センサーを設置・貸与し、急病や事故などの緊急時にボタンで受信センターへ通報、警備会社の出動員や消防が救助にあたる事業です。24時間365日体制で、健康相談にも対応します。対象や利用料・機器の種類は対象者区分（高齢者向け／障害者向け）により異なる可能性があるため、利用にあたっては公式ページで確認してください。', 'ひとり暮らしの高齢者や障害のある方の自宅に、緊急時にボタンで通報できる機器やペンダント、見守り・火災センサーを設置してくれる中央区のサービスです。急病やケガのとき、24時間いつでも受信センターにつながり、警備員や消防が助けに来てくれます。', 'service', '対象となる可能性があるのは、中央区内に住むひとり暮らしの高齢者や高齢者のみの世帯の方（高齢者向けは65歳以上が目安）、または身体障害者手帳1・2級・難病患者でひとり暮らし等の方とされています。日中・夜間に高齢者のみとなる世帯など個別の要件もあるため、対象に該当するかは公式ページや窓口で確認してください。', '機器（本体・緊急ペンダント、希望によりセンサー類）を設置・貸与する現物サービスです。高齢者向けは月額使用料（固定電話回線型式：課税世帯600円・非課税世帯無料、無線型式：課税世帯900円・非課税世帯450円、生活保護受給者等は無料）がかかる場合があります。障害者向けは利用料無料（貸与機器の電気・電話代は利用者負担）とされています。金額や費用負担は対象者区分により異なる可能性があるため公式で確認してください。', '随時受付（公式で確認してください）。', '高齢者向けは、区役所4階の高齢者福祉課またはおとしより相談センターの窓口で申請でき、郵送での受付も可能とされています。障害者向けは障害者福祉課が窓口です。申請受付後、区が委託した設置業者が自宅を訪問し、システムの説明と機器の設置を行うとされています。詳しい手続きは公式ページや担当課で確認してください。', '申請書のほか、該当する場合は就労申立書、登録内容変更届などの様式が必要とされています。詳細は公式ページや担当課で確認してください。', FALSE, '中央区 福祉保健部 高齢者福祉課 高齢者サービス係（障害者向けは障害者福祉課 相談支援係）', '03-3546-5355', 'https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/koreisyasetai/kinkyu.html', 'https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/koreisyasetai/kinkyu.html', '緊急通報システム - 中央区', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は中央区公式サイト(2026-06-26確認)に基づく概要です。対象要件・利用料・機器の種類・申請方法は変更される場合があり、対象者区分により異なります。最新の正確な内容は必ず公式ページまたは担当課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
