insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-chuo-emergency-alert","status":"published","title":"緊急通報システム（中央区）","officialUrl":"https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/koreisyasetai/kinkyu.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-chuo-emergency-alert:dG9reW8tY2h1by1lbWVyZ2VuY3ktYWxlcnR857eK' from public.support_programs sp where sp.slug='tokyo-chuo-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'minato'), 'tokyo-minato-emergency-alert', '救急通報システム（港区）', '港区が、ひとり暮らし等の高齢者の自宅にペンダント型の無線発報機や熱感知器・開閉センサーを設置し、急病・事故・火災などの緊急時に事業者へ通報して警備員の駆けつけや救急車の要請につなげる、見守り・安否確認のための区独自の事業です。', 'ひとり暮らしなどの高齢者の家に、緊急ボタン（ペンダント）やセンサーを取り付け、急に具合が悪くなったときや火災のときに、ボタンやセンサーで事業者へ自動的に知らせて、警備員が駆けつけたり救急車を呼んだりしてくれる、港区の見守りのしくみです。費用はかからないと案内されています。対象や手続きの詳しいことは港区のページで確認してください。', 'service', '港区内に住むひとり暮らしの高齢者や高齢者のみの世帯などが対象となる可能性があります。公式情報では、65歳以上のひとり暮らし高齢者、または家族全員が65歳以上の高齢者世帯の方が対象とされています。日中長時間ひとりになる方なども相談できる場合があります。具体的な対象要件は港区の公式ページで確認してください。なお、障害のある方向けには別事業として「障害者緊急通報システム事業」があります。', '設置・利用にあたっての費用負担はないもの（無料）と公式で案内されています。詳細は港区の公式ページで確認してください。', NULL, '電子申請、郵送、または高齢者支援課窓口への来所により申し込めると公式で案内されています。申込者本人を確認できるもの（運転免許証やマイナンバーカード等）が必要とされ、自宅玄関の合鍵を事業者に預ける必要があるとされています。申込後、区が生活状況等を調査のうえ利用可否を決定するとされています。最新の手続きは港区の公式ページで確認してください。', '申込者本人を確認できるもの（運転免許証やマイナンバーカード等）が必要と公式で案内されています。詳細は港区の公式ページで確認してください。', TRUE, '港区 保健福祉支援部 高齢者支援課 在宅支援係', '03-3578-2111', 'https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kinkyutsuho.html', 'https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kinkyutsuho.html', '港区ホームページ／救急通報システム', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationMethodText']::text[], '本情報は港区公式サイト（確認日2026-06-26）に基づく概要です。対象要件・利用料・機器の種類・申込手続きは変更される場合があるため、利用にあたっては必ず港区の公式ページおよび高齢者支援課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
