insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-minato-emergency-alert","status":"published","title":"救急通報システム（港区）","officialUrl":"https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kinkyutsuho.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-minato-emergency-alert:dG9reW8tbWluYXRvLWVtZXJnZW5jeS1hbGVydHzm' from public.support_programs sp where sp.slug='tokyo-minato-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinjuku'), 'tokyo-shinjuku-emergency-alert', '高齢者緊急通報システム（新宿区）', '新宿区が行う高齢者向けの緊急通報・見守り支援事業です。ひとり暮らし等の高齢者の自宅に緊急通報の本体機器・ペンダント・開閉センサー（希望者）・住宅用火災警報器を設置し、急病や事故などの緊急時にボタンを押す、またはセンサーが一定時間反応しないことで警備会社が確認・出動する仕組みです。対象や利用料・機器の種類は公式ページでご確認ください。', 'ひとり暮らしなどの高齢者の家に、緊急ボタンや見守りセンサーを設置する新宿区のサービスです。急に体調が悪くなったり転んだりしたとき、ボタンを押すか、センサーが動きを感知しないことで警備会社に連絡が行き、必要なときは助けに来てくれます。', 'service', 'おおむね65歳以上で、ひとり暮らしの方または65歳以上のみの世帯の方のうち、慢性疾患があるなど日常生活で常時注意を要する方が対象となる可能性があります。具体的な対象要件は公式ページでご確認ください。', '緊急通報の本体機器・ペンダント・住宅用火災警報器を設置し、希望者には開閉センサー（見守りセンサー）も設置されます。緊急時はボタン押下やセンサーの無反応を警備会社が検知し、確認のうえ必要に応じて出動します。', '公式ページに申込期限の明記はありません。詳細は問い合わせ窓口でご確認ください。', '各高齢者総合相談センター、高齢者支援課（区役所本庁舎2階）、または各特別出張所で申請書を記入して申し込みます。詳しい手続きは公式ページや問い合わせ窓口でご確認ください。', '申請書の記入が必要です。そのほかの必要書類は申請窓口でご確認ください。', FALSE, '新宿区 福祉部 高齢者支援課 高齢者支援係', '03-5273-4305', 'https://www.city.shinjuku.lg.jp/fukushi/file05_02_00018.html', 'https://www.city.shinjuku.lg.jp/fukushi/file05_02_00018.html', '高齢者緊急通報システム - 新宿区', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '対象年齢・要件、利用料（設置時費用や減免の有無）、設置される機器の種類は年度や状況により異なる場合があります。最新かつ正確な内容は新宿区の公式ページや問い合わせ窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
