insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-shinjuku-emergency-alert","status":"published","title":"高齢者緊急通報システム（新宿区）","officialUrl":"https://www.city.shinjuku.lg.jp/fukushi/file05_02_00018.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-shinjuku-emergency-alert:dG9reW8tc2hpbmp1a3UtZW1lcmdlbmN5LWFsZXJ0' from public.support_programs sp where sp.slug='tokyo-shinjuku-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'bunkyo'), 'tokyo-bunkyo-emergency-alert', '救急通報システム（文京区）', '文京区の区独自事業で、おおむね65歳以上のひとり暮らし等で身体上慢性的な疾患があるなど常時注意を要する方を対象に、自宅にペンダント等の緊急通報装置を設置・貸与する見守りサービス。急病など救急時にボタンを押すと、区が契約する民間会社の受信センター（看護師等）を通じて東京消防庁へ通報され、警備員等の駆けつけ員も派遣される。24時間の相談機能や月1回程度の健康確認連絡もあります。利用には主治医による必要性の確認書が必要で、対象となるかは公式で確認が必要です。', 'ひとり暮らしの高齢者などが、急に倒れたときにペンダントのボタンを押すだけで助けを呼べる仕組みです。区が用意した装置を家に設置し、押すと専門のセンターを通じて救急車の手配や駆けつけ対応をしてもらえます。対象になるかどうかは区の窓口で確認してください。', 'service', 'おおむね65歳以上のひとり暮らし等で、身体上慢性的な疾患があるなど常時注意を要する状態であり、救急事態に陥った時に自分で救急要請ができない状態になる可能性がある方が対象となる可能性があります。対象要件は公式で確認してください。なお18〜64歳の重度身体障害者等の方は別事業「救急代理通報システム」の対象となる可能性があります。', '緊急通報装置（ペンダント等）の設置・貸与による見守り・通報サービス。利用料は月350円（住民税非課税世帯は免除）と公式に記載されていますが、金額・負担区分は変更される場合があるため公式で確認してください。', '公式ページに申請期限の記載は確認できませんでした（随時受付と思われますが、公式で確認してください）。', '高齢福祉課高齢者相談係へ電話または来庁のうえ申請します。申請にあたっては主治医による救急通報システムの必要性についての確認書が必要です。詳細・最新の手続きは公式ページで確認してください。', '主治医による救急通報システムの必要性についての確認書。その他の必要書類は申請窓口で確認してください。', FALSE, '文京区 福祉部 高齢福祉課 高齢者相談係', '03-5803-1382', 'https://www.city.bunkyo.lg.jp/b017/p003178.html', 'https://www.city.bunkyo.lg.jp/b017/p003178.html', '救急通報システム | 文京区', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は文京区公式サイトの掲載内容（2026-06-26確認）に基づく概要です。対象要件・利用料・機器の種類・手続きは変更される場合があり、また個々の状況により対象可否が異なります。最新かつ正確な情報は必ず公式ページまたは窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
