insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'taito'), 'tokyo-taito-emergency-alert', '台東区 民間緊急通報システム', '台東区が実施する高齢者向けの緊急通報・見守り事業。自宅に設置した専用機器の緊急ボタンを押すと民間受信センター（看護師等）に接続され、急病や事故などの緊急時に救急車・消防車の要請や警備員の派遣、緊急連絡先への連絡を受けられる可能性があります。平常時も日常的な健康相談や月1回のお伺い電話による見守りが受けられる場合があります。', 'ひとり暮らしなどの高齢者の自宅に緊急通報の機器を設置し、ボタンを押すと受信センターにつながって、急病や事故のときに助けを呼べるようにする台東区の見守りサービスです。ふだんも健康相談や月1回の電話による安否確認が受けられる場合があります。対象になるかどうかや料金は、必ず台東区の公式ページや高齢福祉課でご確認ください。', 'service', '区内在住の65歳以上で、ひとり暮らしまたは高齢者のみの世帯の方のうち、慢性疾患がある等、日常生活を営む上で常時注意を要する方が対象となる可能性があります。対象要件の詳細は台東区の公式ページで確認してください。', '利用料は月額制で、住民税課税世帯は600円、非課税世帯は300円（いずれも別途消費税）。6ヶ月分をまとめて自動口座振替で支払う仕組みと公式で案内されています（金額・条件は変更される可能性があるため公式で確認してください）。', '申請期限に関する記載は公式ページで確認できませんでした。', '高齢福祉課総合相談・給付担当（電話：03-5246-1224）へ問い合わせのうえ申請します。申請窓口で要件に該当するかの調査が行われると公式に記載されています。具体的な申請手続きの流れ・必要書類は公式ページまたは担当課でご確認ください。', '必要書類に関する具体的な記載は公式ページで確認できませんでした。担当課にご確認ください。', FALSE, '台東区 高齢福祉課 総合相談・給付担当', '03-5246-1224', 'https://www.city.taito.lg.jp/kenkohukusi/korei/serviceannai/kyuuhujosei/minkankinkyuutuuhou.html', 'https://www.city.taito.lg.jp/kenkohukusi/korei/serviceannai/kyuuhujosei/minkankinkyuutuuhou.html', '民間緊急通報システム - 台東区', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable', 'applicationMethodText']::text[], '本情報は台東区公式ページ（2026-06-26確認）に基づく概要です。対象要件・利用料・機器の種別・申請手続きは変更される場合があるため、最新の内容は必ず台東区の公式ページまたは高齢福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
