insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-taito-emergency-alert","status":"published","title":"台東区 民間緊急通報システム","officialUrl":"https://www.city.taito.lg.jp/kenkohukusi/korei/serviceannai/kyuuhujosei/minkankinkyuutuuhou.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-taito-emergency-alert:dG9reW8tdGFpdG8tZW1lcmdlbmN5LWFsZXJ0fOWP' from public.support_programs sp where sp.slug='tokyo-taito-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'sumida'), 'tokyo-sumida-emergency-alert', '墨田区 救急通報システム（旧・緊急通報システム）', '墨田区にお住まいの65歳以上のひとり暮らし又は65歳以上のみの世帯の高齢者を対象に、自宅の専用通報機やペンダント型のボタンを押すと民間事業者の受信センターへ連絡され、専門の現場派遣員が自宅に急行し救急車の手配など必要な救援を行う区の事業です（24時間365日対応）。在宅時の日常生活を見守る安否確認センサも用意されています。対象や利用料・機器の種別には区分があるため、詳細は墨田区公式でご確認ください。', 'ひとり暮らしなどの高齢者が、急病やけが・火災のときに、ボタンを押すだけで受信センターへ連絡でき、係員が自宅へかけつけてくれる墨田区のしくみです。普段の見守りのためのセンサも使えます。費用や対象は区分があるので、墨田区の公式ページで確認してください。', 'service', '墨田区内に住所を有する65歳以上のひとり暮らし、又は65歳以上の者のみの世帯の高齢者が対象となる可能性があります（日中又は夜間にひとり暮らし・高齢者のみとなる世帯を含む場合があります）。固定電話又は携帯電話を利用していることなどの条件が示されています。具体的な年齢・世帯・健康（ペースメーカー使用時の注意等）・所得などの要件は墨田区公式でご確認ください。', 'サービス（緊急時の通報・現場派遣・安否確認等の見守り）として提供されます。利用料には区分があり、公式では救急通報機が固定電話型式で月額0円・500円・2,618円、無線型式で月額0円・1,100円・3,718円、安否確認センサが月額1,000円といった例が示されています。実際の自己負担額・区分は墨田区公式でご確認ください。', '随時受付と考えられますが、申請期限・受付方法は墨田区公式でご確認ください。', '墨田区高齢者福祉課支援係への申請・相談により利用を申し込みます。申請書のほか、電話回線確認表・承諾書、設置承諾書などの提出が必要とされています。原則として自宅の鍵の複製を作成し預ける運用が案内されています。最新の手続き・必要書類は墨田区公式でご確認ください。', '申請書、電話回線確認表・承諾書、設置承諾書など（公式ページにPDF・Excel様式の案内あり）。詳細は墨田区公式でご確認ください。', FALSE, '墨田区 高齢者福祉課 支援係', '03-5608-6168', 'https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/hitorigurasi/mansei_sikkan.html', 'https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/hitorigurasi/mansei_sikkan.html', '慢性疾患をもっている方の緊急時にそなえて（［旧緊急通報システム］救急通報システム・火災安全システム） 墨田区公式ウェブサイト', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable']::text[], '本情報は墨田区公式ウェブサイト（2026-06-26確認）に基づく概要です。対象要件・利用料・機器種別・申請手続きは変更される場合があるため、利用前に必ず墨田区高齢者福祉課（支援係）または公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
