insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-sumida-emergency-alert","status":"published","title":"墨田区 救急通報システム（旧・緊急通報システム）","officialUrl":"https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/hitorigurasi/mansei_sikkan.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-sumida-emergency-alert:dG9reW8tc3VtaWRhLWVtZXJnZW5jeS1hbGVydHzl' from public.support_programs sp where sp.slug='tokyo-sumida-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'koto'), 'tokyo-koto-emergency-alert', '高齢者救急通報システム（緊急通報・見守り機器の設置）', '江東区が、ひとり暮らし等の高齢者宅に主装置・通報用ペンダント・各種センサーを設置し、急病や事故などの緊急時にペンダント押下で委託警備会社へ通報、警備員のかけつけや消防署への通報につなげる見守り・緊急通報事業です。対象や利用料の詳細は公式での確認が必要です。', 'ひとり暮らしなどの高齢者の家に、緊急通報ボタン（ペンダント）やセンサーを取り付ける江東区のサービスです。急に具合が悪くなったときなどにボタンを押すと、警備会社に連絡が行き、警備員がかけつけたり消防署へ通報したりします。利用には月額の負担があります（非課税の方は割引、生活保護の方は無料の場合があります）。申し込みは長寿サポートセンターや区役所の長寿応援課で受け付けています。', 'service', '65歳以上のひとり暮らし・高齢者のみの世帯、または日中など長時間ひとりになる65歳以上の方で、慢性疾患があるなど日常生活を営む上で常時注意を要する状態にあり、携帯電話・固定電話等の連絡手段がある方が対象とされています。詳しい要件は公式ページでご確認ください。なお64歳以下で障害者福祉を希望の方には、別途「重度身体障害者等救急通報システム」が用意されています。', '利用者負担は月額1,500円（住民税非課税者は750円、生活保護受給者等は免除）とされています。金額は変更される場合があるため公式で確認してください。', '申請期限の定めは公式ページに明記されていません（申請から設置まで1〜2か月程度）。', '区内21か所の長寿サポートセンター、または江東区役所長寿応援課シニア活躍支援係（本庁舎3階8番）で申請します。申請から設置まで1〜2か月程度かかるとされています。詳細は公式ページでご確認ください。', '申請にあたって必要となる書類の詳細は公式ページに個別の明記がありません。長寿サポートセンターまたは長寿応援課でご確認ください。', FALSE, '江東区 福祉部 長寿応援課 シニア活躍支援係', '03-3647-9468', 'https://www.city.koto.lg.jp/211102/fukushi/koresha/service/jisshi/6592.html', 'https://www.city.koto.lg.jp/211102/fukushi/koresha/service/jisshi/6592.html', '高齢者救急通報システムの設置 - 江東区', '2026-06-24', 'high', ARRAY['requiredDocumentsText', 'applicationDeadlineText']::text[], '対象者・利用料・設置機器などの詳細は変更される場合があります。必ず江東区の公式ページや窓口で最新情報をご確認ください。なお64歳以下で障害をお持ちの方向けには別制度（重度身体障害者等救急通報システム）があり、本ページとは申請窓口・要件が異なります。当サイトは申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
