insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinagawa'), 'tokyo-shinagawa-emergency-alert', '品川区高齢者救急代理通報システム', '品川区が行う、ひとり暮らし高齢者等の自宅に救急ペンダントや生活リズムセンサー・火災センサーを設置し、緊急時に警備会社へ通報・駆けつけによる救助や見守りを行う区独自の事業です。', '品川区が、ひとり暮らしなどの高齢者の家に通報ボタン付きのペンダントやセンサーを設置するサービスです。急に具合が悪くなったときにボタンを押したり、センサーが異常を感知したりすると、警備会社に連絡が行き、係員が駆けつけて救急車を呼ぶなどの手助けをしてくれます。月々の利用料金はかからないとされています。申請は支え愛・ほっとステーションや在宅介護支援センターなどで受け付けています。', 'service', '区内に住所がある65歳以上のひとり暮らし、または高齢者のみの世帯、日中や夜間に独りになる高齢者世帯の方が対象となる可能性があります。対象年齢・世帯要件の詳細は公式で確認してください。', '公式ページには「月々のご利用料金はかかりません」と記載されています。機器の種類や設置に関する費用負担の有無など詳細は公式で確認してください。', NULL, '申請書(および機器設置チェックシート)を、お近くの支え愛・ほっとステーション、在宅介護支援センター、または区役所の窓口へ提出します。電子申請も受け付けています。要介護認定等を受けている方は在宅介護支援センターでの申請が案内されています。詳しい手続きは公式ページや問い合わせ先で確認してください。', '申請書、機器設置チェックシート(公式ページに基づく。最新の必要書類は窓口・公式で確認してください)。', TRUE, '品川区 福祉計画課 災害要配慮者支援担当', '03-5742-3852', NULL, 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-koureisya/kenkou-koureisya-anshinkurashi/hpg000008061.html', '品川区高齢者救急代理通報システム｜品川区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '対象要件・利用料・機器の種類・申請方法は変更される場合があります。利用を検討する際は、必ず品川区の公式ページまたは問い合わせ先で最新情報をご確認ください。当サイトは申請の代行は行いません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
