insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-shinagawa-emergency-alert","status":"published","title":"品川区高齢者救急代理通報システム","officialUrl":"https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-koureisya/kenkou-koureisya-anshinkurashi/hpg000008061.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-shinagawa-emergency-alert:dG9reW8tc2hpbmFnYXdhLWVtZXJnZW5jeS1hbGVy' from public.support_programs sp where sp.slug='tokyo-shinagawa-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'meguro'), 'tokyo-meguro-emergency-alert', 'ひとりぐらし・高齢者世帯の非常通報システム（目黒区）', '目黒区が、ひとりぐらしの高齢者世帯等を対象に、自宅へ非常通報機（固定型・通信機能搭載型）やペンダント型通報機を設置し、急病・事故時にボタンで通報できる仕組みを提供する事業です。専用通報機のボタンを押すとコールセンターに通報され、緊急時には対応が行われるとされています。希望に応じて在宅時の異常を判断して自動通報する「生活リズムセンサー」も追加できると公式に案内されています。対象や要件は公式ページでご確認ください。', 'ひとりぐらしの高齢者などの自宅に、緊急ボタン付きの通報機やペンダントを置き、急に具合が悪くなったときにボタンを押すと、コールセンターに連絡できる目黒区の仕組みです。必要なときの対応をしてくれるとされています。利用できるかどうかや料金は、目黒区の公式ページや高齢福祉課でご確認ください。', 'service', '目黒区で「ひとりぐらし等高齢者登録」をされている、ひとりぐらしの高齢者や高齢者のみの世帯の方などが対象となる可能性があります。生活リズムセンサーは、ひとりぐらしかつ近隣に親族が居住していない方で常時寝たきりでない方が対象と公式に記載されています。具体的な対象年齢・要件は公式に明記がない部分があるため、目黒区の公式ページや高齢福祉課でご確認ください。', '利用料は月額286円（生活リズムセンサーをあわせて利用する場合は491円）と公式に記載されています。生活保護を受けている方、住民税が非課税の世帯の方は無料とされています（公式ページで要確認）。', '公式ページに申請期限の記載は確認できませんでした。', '非常通報システム利用申請書（借家等にお住まいで生活リズムセンサーを申請する場合は家屋所有者の機器設置承諾書も）を、各地域包括支援センターまたは高齢福祉課へ提出する方法が公式に案内されています。申請書はPDFでダウンロードできます。最新の手続きは公式ページでご確認ください。', '（1）非常通報システム利用申請書、（2）家屋所有者非常通報システム機器設置承諾書（借家等に居住しているかたが生活リズムセンサーを申請する場合のみ）。', FALSE, '目黒区 高齢福祉課 在宅事業係', '03-5722-9839', 'https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/tsuho.html', 'https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/tsuho.html', 'ひとりぐらし・高齢者世帯の非常通報システム | 目黒区', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'onlineApplicationAvailable', 'applicationDeadlineText']::text[], '本情報は目黒区公式サイト（確認日2026-06-26、ページ最終更新2025-12-11）に基づく概要です。対象要件・利用料・機器の種類・申請方法などは変更される場合があります。実際の利用可否や手続きは必ず目黒区高齢福祉課または各地域包括支援センターにご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
