insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-meguro-emergency-alert","status":"published","title":"ひとりぐらし・高齢者世帯の非常通報システム（目黒区）","officialUrl":"https://www.city.meguro.tokyo.jp/koureifukushi/kenkoufukushi/koureisha/tsuho.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-meguro-emergency-alert:dG9reW8tbWVndXJvLWVtZXJnZW5jeS1hbGVydHzj' from public.support_programs sp where sp.slug='tokyo-meguro-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'ota'), 'tokyo-ota-emergency-alert', '高齢者救急代理通報システム（大田区）', 'ひとり暮らしの高齢者などの自宅にペンダント型無線発報器を設置し、急病やケガのときにボタンを押すと区の受託事業者の受信センターへ通報され、救急通報とともに専門の警備員が自宅に駆けつける、大田区独自の緊急通報・見守り事業です。', '65歳以上のひとり暮らしや高齢者だけの世帯で、病気がちなどで日常的に見守りが必要な方が対象となる可能性があります。胸にかけたペンダントのボタンを押すと、24時間体制の受信センターに通報が届き、警備員が自宅へ駆けつけてくれます。利用には区への申請が必要で、対象要件や費用は公式ページや窓口でご確認ください。', 'service', '65歳以上のひとり暮らし、または高齢者のみの世帯で、病弱等により日常生活を営むうえで常時注意を要する方が対象となる可能性があります。令和8年4月からは課税世帯も対象に拡大したとされています。詳しい対象要件は大田区の公式ページや相談窓口でご確認ください。', 'ペンダント型無線発報器等の機器を設置・貸与し、受信センターへの通報と警備員の駆けつけ・見守りを提供するサービスです。令和8年4月からは熱中症アラートが標準装備、ライフリズムセンサーがオプションとして追加されるとされています。利用料の有無・金額は公式ページに明記がないため、窓口でご確認ください。', '公式ページに明記なし（随時受付と考えられますが、詳細は窓口でご確認ください）。', '各地域包括支援センター（高齢者の相談窓口）へ申請します。地域ごとの地域福祉課高齢者地域支援担当が問い合わせ先となります（例：大森地域福祉課 03-5764-0658）。', '公式ページに明記なし。必要書類は申請窓口でご確認ください。', FALSE, '各地域福祉課 高齢者地域支援担当（例：大森地域福祉課）', '03-5764-0658', 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/kinkyutuhou.html', 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/kourei/kyufu/kinkyutuhou.html', '大田区ホームページ：高齢者救急代理通報システム', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は大田区公式サイトをもとに作成しています。対象要件・費用・機器の詳細は変更される場合があるため、必ず公式ページまたは窓口で最新情報をご確認ください。当サイトは申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
