insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'setagaya'), 'tokyo-setagaya-emergency-alert', '救急通報システム「愛のペンダント」（世田谷区）', '世田谷区が、ひとり暮らし等の高齢者に対し、急病・事故などの緊急時にペンダント型ボタンを押して通報できる機器を設置・貸与する事業です。ボタンを押すと民間受信センターへ通報され、必要に応じて救急車の出動要請や警備会社の現場派遣員がかけつけ、日常の見守りにもつながります。対象や利用料金などの詳細は公式ページでの確認が必要です。', 'ひとり暮らしなどの高齢者の自宅に、緊急時にボタンを押して助けを呼べるペンダント型の機器を設置する世田谷区のサービスです。急病やけがのときにボタンを押すと受信センターへつながり、必要に応じて救急車の手配や警備員のかけつけが行われ、日ごろの見守りにもなります。対象になるかや費用は、お住まいの地域の総合支所保健福祉課や高齢福祉課にお問い合わせください。', 'service', '65歳以上で、ひとりぐらし・高齢者のみ世帯・日中独居世帯であり、慢性疾患があるなど日常生活を営む上で常時注意を要する方が対象となる可能性があります（日中独居世帯には所得制限ありとされています）。具体的な対象要件は世田谷区の公式ページで確認してください。', '機器の設置・貸与（サービス提供）です。利用者負担金として設置時8,000円、光回線等を利用する場合は非常用電源に別途上限4,000円がかかるとされています（介護保険段階により免除がある場合あり）。', '申請期限に関する記載は公式ページで確認できませんでした。随時受付の可能性がありますが、詳細は窓口にご確認ください。', '各総合支所保健福祉課への申請・問い合わせにより手続きを行うとされています。詳しい申請方法・必要書類は公式ページまたは下記窓口で確認してください。', '必要書類に関する具体的な記載は公式ページで確認できませんでした。各総合支所保健福祉課にご確認ください。', FALSE, '世田谷区 高齢福祉課（または各総合支所保健福祉課）', '03-5432-2407', 'https://www.city.setagaya.lg.jp/02082/2400.html', 'https://www.city.setagaya.lg.jp/02082/2400.html', '救急通報システム「愛のペンダント」| 世田谷区公式ホームページ', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText', 'benefitAmountText', 'targetPeople']::text[], '本内容は世田谷区公式ページ（2026-06-26確認）に基づく概要です。対象要件・利用料金・機器の種別・申請方法は変更される場合があるため、必ず公式ページおよび各総合支所保健福祉課でご確認ください。本サービスは申請により対象と認められた場合に利用できるもので、受給・利用を保証するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
