insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-setagaya-emergency-alert","status":"published","title":"救急通報システム「愛のペンダント」（世田谷区）","officialUrl":"https://www.city.setagaya.lg.jp/02082/2400.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-setagaya-emergency-alert:dG9reW8tc2V0YWdheWEtZW1lcmdlbmN5LWFsZXJ0' from public.support_programs sp where sp.slug='tokyo-setagaya-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shibuya'), 'tokyo-shibuya-emergency-alert', '高齢者救急通報システムの設置（渋谷区）', '渋谷区が、ひとり暮らしの高齢者などの自宅に救急通報装置を設置する事業です。急に具合が悪くなったときやけがをしたときに救急通報ボタンを押すと民間の受信センターにつながり、安否確認のうえ、緊急時には救急車の要請や緊急出動員の駆けつけ対応を行います。希望に応じてトイレなどの扉にライフリズムセンサーを設置し、一定時間扉の開閉がないと自動で通報する見守り機能も利用できる可能性があります。対象や費用、機器の種類などの詳細は渋谷区の公式ページでご確認ください。', 'ひとり暮らしの高齢者などの家に、急病やけがのときにボタンを押して助けを呼べる装置を取り付けてもらえる渋谷区のサービスです。ボタンを押すと係の人につながり、必要なときは救急車を呼んだり、家まで駆けつけたりしてくれます。トイレの扉が長く開かないと自動で知らせる見守りも選べる場合があります。', 'service', '区内在住で65歳以上のひとり暮らし、または65歳以上のみの世帯の方が対象となる可能性があります。日中高齢者のみとなる世帯や、同居の家族が疾病などで緊急時の対応が困難な世帯も対象となる場合があります。対象要件の詳細は渋谷区の公式ページでご確認ください。なお重度障害の方は、別の事業として障がい者向けの救急通報システム（無料・ペンダント型）が用意されている場合があります。', '費用は月額290円（税込・ライフリズム見守りサービスなしの場合）または月額410円（税込・ライフリズム見守りサービスありの場合）に加え、別途月額300円程度の通信費が発生する場合があります。金額は変更される可能性があるため、最新の料金は公式ページでご確認ください。', '申請期限は公式ページに明記されていません。詳細は渋谷区にご確認ください。', '窓口申請・郵送申請のほか、辞退については スマート申請が利用できる場合があります。申請の際は「渋谷区高齢者救急通報システム利用申請書」「申請者情報確認書」などの提出が求められる可能性があります。詳しい手続きは高齢者福祉課サービス事業係または地域包括支援センターにご確認ください。', '渋谷区高齢者救急通報システム利用申請書、申請者情報確認書など（変更時は変更申請書、辞退時は辞退申請書）。必要書類は公式ページでご確認ください。', FALSE, '渋谷区 福祉部 高齢者福祉課 サービス事業係', '03-3463-1873', 'https://www.city.shibuya.tokyo.jp/kenko/koreisha-seikatsu/koreisha-zaitaku/k_tsuho.html', 'https://www.city.shibuya.tokyo.jp/kenko/koreisha-seikatsu/koreisha-zaitaku/k_tsuho.html', '高齢者救急通報システムの設置 | 渋谷区ポータル', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は2026年6月26日時点で渋谷区公式ページを確認して作成しています。対象要件・費用・機器の種類・申請方法は変更される場合があります。申請の可否や詳細は必ず渋谷区の公式ページや担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
