insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-shibuya-emergency-alert","status":"published","title":"高齢者救急通報システムの設置（渋谷区）","officialUrl":"https://www.city.shibuya.tokyo.jp/kenko/koreisha-seikatsu/koreisha-zaitaku/k_tsuho.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-shibuya-emergency-alert:dG9reW8tc2hpYnV5YS1lbWVyZ2VuY3ktYWxlcnR8' from public.support_programs sp where sp.slug='tokyo-shibuya-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nakano'), 'tokyo-nakano-emergency-alert', '緊急通報システム（中野区）', '中野区が、ひとり暮らし等の高齢者や重度身体障害者の自宅に緊急通報装置・見守りセンサー・火災センサー・無線ペンダント等を貸与し、急病・事故・火災時に民間受信センターへ通報して見守る区独自の事業です。対象や利用料金などの詳細は公式ページでご確認ください。', 'ひとり暮らしのお年寄りや重い障害のある方の家に、ボタンを押すだけで助けを呼べる装置やペンダント、見守り・火災センサーを取り付ける中野区のサービスです。急な体調不良や火事のとき、24時間つながる受信センターに連絡が届き、必要に応じて消防などが駆けつけます。利用には月300円〜1,300円ほどの費用がかかる場合があります。', 'service', '日常生活で常時見守りを必要とする65歳以上のひとり暮らし・高齢者のみ世帯・日中独居の方、または18歳以上の重度身体障害者（1・2級）で同様の状況の方などが対象となる可能性があります。具体的な対象要件は公式ページや窓口でご確認ください。', '利用料金は月額300円〜1,300円程度で、慢性疾患の有無・住民税の課税状況・対象区分により異なると公式で案内されています（例：特定の慢性疾患がある方は課税世帯600円・非課税世帯300円、日中独居の方は課税世帯1,300円・非課税世帯650円）。最新の金額は公式ページでご確認ください。', NULL, '高齢者（65歳以上）は地域包括支援センター、障害のある方は障害者福祉相談窓口（区役所3階5番窓口）で申請する方法が公式で案内されています。手続きの詳細・必要書類は事前に担当窓口へご確認ください。', '必要書類は公式ページに明記がないため、申請窓口（地域包括支援センターまたは障害者福祉相談窓口）にご確認ください。', FALSE, '中野区 地域包括ケア推進課 在宅サービス係（区役所3階3番窓口）', '03-3228-5632', NULL, 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/kinkyutsuho.html', '緊急通報システム | 中野区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '対象要件・利用料金・申請方法は変更される場合があります。最新かつ正確な情報は必ず中野区の公式ページでご確認ください。当サイトは申請の代行や受給の保証は行いません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
