insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'suginami'), 'tokyo-suginami-emergency-alert', '高齢者緊急通報システム（杉並区）', '杉並区が、ひとり暮らし等の高齢者の自宅に、ペンダント型の救急ボタン・安心センサー（人の動きを感知する赤外線センサー）・火災センサー・受信センターへの通報機を貸与・設置する区独自の緊急通報/見守り事業です。急病や事故の際にボタンを押す、または一定時間動きがないと自動で通報され、対応につながる可能性があります。対象や利用料・機器の種別は公式ページで確認してください。', 'ひとり暮らしなどの高齢者の家に、押すと助けを呼べるペンダント型ボタンや、動きがないと自動で知らせるセンサー、火災センサーを区が取り付けてくれる見守りの仕組みです。急な病気や事故のときに通報され、対応につながる可能性があります。65歳以上で高齢者だけの世帯などが対象になる場合があります。利用料は収入に応じてかかることがあります。申し込みや詳しい条件は杉並区の窓口やケア24に相談してください。', 'service', '区内に住所を有する65歳以上の高齢者のみの世帯で、慢性疾患があるなど常時注意を要する方が対象となる可能性があります。具体的な要件は杉並区公式ページで確認してください。', '利用料は所得に応じて負担あり（無料～月額600円）と公式に記載。所得区分の詳細は要確認。', '随時（公式ページで確認してください）', '区役所高齢者在宅支援課高齢者見守り連携係、またはお近くの高齢者総合相談窓口ケア24（地域包括支援センター）へ申し込みます。詳細・申請書は杉並区公式ページで確認してください。', '申請書等が必要となる可能性があります。必要書類の詳細は杉並区公式ページまたは窓口で確認してください。', FALSE, '杉並区 保健福祉部 高齢者在宅支援課 高齢者見守り連携係', '03-3312-2111', 'https://www.city.suginami.tokyo.jp/guide/koureisha/enjo/1004638.html', 'https://www.city.suginami.tokyo.jp/guide/koureisha/enjo/1004638.html', '高齢者緊急通報システム｜杉並区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は杉並区公式ページ（最終更新2026-04-01）に基づく概要です。対象要件・利用料・機器の種別・必要書類は変更される場合があるため、申請前に必ず杉並区公式ページまたは窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
