insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'toshima'), 'tokyo-toshima-emergency-alert', '高齢者救急通報システム（豊島区）', '豊島区が実施する高齢者向けの救急・見守り支援事業です。ひとり暮らし高齢者などの自宅に緊急通報装置（ペンダント型発信機や空間センサー等）を貸与し、急病・事故時にボタンを押すと民間受信センターへ通報され、救急要請や緊急連絡先への連絡、現場派遣員の駆けつけが行われます。火災の自動通報や24時間365日の健康相談にも対応するとされています。対象や利用料・機器の種類などの詳細は公式ページや担当課で確認してください。', 'ひとり暮らしの高齢者などの家に、ボタンを押すと助けを呼べる緊急通報の機械（ペンダントやセンサー）を区が貸してくれる仕組みです。急に具合が悪くなったときや火事のときに、24時間いつでも受信センターへ通報され、必要に応じて救急の手配や駆けつけが行われます。健康の相談もできるとされています。利用できる条件や費用は区の公式ページで確認してください。', 'service', '65歳以上のひとり暮らし高齢者、または65歳以上の高齢者のみ世帯の方が対象となる可能性があります。日中独居の方（証明書が必要な場合あり）や、自宅の合鍵を事業者に預けられる方も対象となり得ます。対象要件は変更されることがあるため、必ず豊島区公式の案内で確認してください。', '緊急通報装置（ペンダント型発信機・空間センサー等）の貸与・設置と、民間受信センターによる24時間365日の通報・見守り・健康相談などのサービスが受けられるとされています。具体的な機器の種類は公式ページで確認してください。', '公式ページに明確な申請期限の記載は確認できませんでした。詳細は担当課にご確認ください。', '高齢者総合相談センターの窓口、または区の電子申請サービス（インターネット申請）から申し込む方法が案内されています。利用申請書のほか、状況に応じて家主・管理人の承諾書（借家の場合）、慢性疾患証明書、勤務証明書（同居者が勤務している場合）などが必要となる場合があります。詳細は担当課にご確認ください。', '高齢者救急通報システム利用申請書のほか、借家の場合は家主・管理人の承諾書、慢性疾患がある場合は慢性疾患証明書、同居者が勤務している場合は勤務証明書などが必要となる場合があります。自己負担がある方は口座振替依頼書の提出が求められる場合があります。', TRUE, '豊島区 保健福祉部 高齢者福祉課 高齢者事業グループ', '03-4566-2432', NULL, 'https://www.city.toshima.lg.jp/379/kenko/koresha/ippansesaku/1502171054.html', '高齢者救急通報システム - 豊島区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', '対象年齢・世帯要件の詳細', '利用料・自己負担額', '機器の種類の詳細']::text[], '本情報は豊島区公式ページ（2026-06-26確認）に基づく概要です。対象要件・利用料・機器の種類・申請方法は変更されることがあります。最新かつ正確な内容は必ず豊島区の公式案内または担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
