insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-toshima-emergency-alert","status":"published","title":"高齢者救急通報システム（豊島区）","officialUrl":"https://www.city.toshima.lg.jp/379/kenko/koresha/ippansesaku/1502171054.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-toshima-emergency-alert:dG9reW8tdG9zaGltYS1lbWVyZ2VuY3ktYWxlcnR8' from public.support_programs sp where sp.slug='tokyo-toshima-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'kita'), 'tokyo-kita-emergency-alert', '高齢者見守り・緊急通報システム（東京都北区）', '東京都北区が、ひとり暮らしの高齢者などの自宅に緊急通報装置を貸与・設置し、急病や事故などの緊急時にボタン操作で通報できるようにする事業です。看護師等の資格を持ったスタッフが24時間体制で対応し、緊急時には119番通報を行うほか、月1回の安否確認電話があります。オプションで火災安全システム（煙感知型）や安否確認センサの貸与・設置も利用できる場合があります。', 'ひとり暮らしの高齢者などの家に、緊急通報の装置を取り付けてくれる北区のサービスです。急に具合が悪くなったときなどにボタンを押すと、24時間対応の窓口（看護師等）につながり、必要なときは救急車（119番）を呼んでくれます。月に1回の安否確認の電話もあります。利用には毎月の利用料がかかる場合がありますが、住民税非課税の世帯などは無料になります。申し込みは、お住まいの近くの高齢者あんしんセンター（地域包括支援センター）にご相談ください。', 'service', '公式によると、区内に住所を有する65歳以上の一人ぐらしの方、または高齢者（65歳以上）のみの世帯で近隣に親族が居住していない方で、身体上慢性疾患があるなど日常生活を営む上で常時注意を要する方が対象とされています。詳しい対象要件は北区の公式情報や高齢者あんしんセンター（地域包括支援センター）でご確認ください。', '緊急通報装置の貸与・設置（現物サービス）。利用料は月額制で、公式（令和8年度）によると課税世帯は緊急通報システム月額310円（固定電話利用）または410円（機器内蔵回線利用）、火災安全システム月額37円、安否確認センサ月額55円などとされています。住民税非課税世帯・生活保護世帯は無料です。最新の金額や負担条件は必ず公式でご確認ください。', '公式ページに申請期限の記載は確認できませんでした。随時受付の可能性がありますが、詳細は北区にご確認ください。', '公式によると、最寄りの高齢者あんしんセンター（地域包括支援センター）に相談して申し込む流れとなります。お薬手帳などの提出を求められる場合があります。詳しい手続きは北区の公式情報または下記問い合わせ先でご確認ください。', '公式によると、お薬手帳などが必要になる場合があります。必要書類の詳細は申し込み時に高齢者あんしんセンターや高齢福祉課でご確認ください。', FALSE, '東京都北区 福祉部 高齢福祉課 高齢相談係', '03-3908-9083', 'https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008611.html', 'https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008611.html', '高齢者見守り・緊急通報システム｜東京都北区', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は北区公式サイトの掲載内容（2026-06-26時点、令和8年度版・更新日2026-04-01）を要約したものです。対象要件・利用料・機器の種類・手続きは変更される場合があるため、最終的な内容は必ず北区の公式情報および高齢福祉課・高齢者あんしんセンターでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
