insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-kita-emergency-alert","status":"published","title":"高齢者見守り・緊急通報システム（東京都北区）","officialUrl":"https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008611.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-kita-emergency-alert:dG9reW8ta2l0YS1lbWVyZ2VuY3ktYWxlcnR86auY' from public.support_programs sp where sp.slug='tokyo-kita-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'arakawa'), 'tokyo-arakawa-emergency-alert', '緊急通報システム（みまもりネットワークサービス）', '荒川区内にお住まいのひとり暮らし高齢者等を対象に、自宅に専用の緊急通報機器やセンサーを設置し、急病・事故などの緊急時に受信センターへ通報して警備員の駆けつけ・119番通報につなげる区の見守りサービスです。生活リズムセンサーや人感センサーにより、一定時間動きが感知できない場合は自動的に通報する機能もあります。対象や利用料、機器の種別などの詳細は荒川区公式サイトでご確認ください。', 'ひとり暮らしの高齢者などのお宅に、緊急時にボタンを押すと助けを呼べる機器や、動きを見守るセンサーを設置する荒川区のサービスです。急な体調不良や転倒のときに、受信センターへ自動・手動で連絡が届き、警備員の駆けつけや119番通報につながります。', 'service', '荒川区内にお住まいの65歳以上で、(1)ひとり暮らし、(2)日中独居（1日4時間以上）、(3)高齢者のみ世帯（双方とも65歳以上）のいずれかに該当し、日常生活を営む上で不安を感じている方が対象となる可能性があります。重度身体障がいのある方は別途、障害者福祉課所管の緊急通報サービスの対象となる場合があります。対象要件は変わることがあるため、最新の条件は公式で確認してください。', '利用料金は住民税課税の方で月額200円または300円（固定電話回線の有無により異なる）、住民税非課税の方は0円とされています。電池交換時には消耗状況に応じて数百円から数千円程度の実費がかかる場合があります。金額は変更されることがあるため公式で確認してください。', '随時受付（公式に明確な締切の記載は確認できませんでした。詳細は窓口にご確認ください）。', '高齢者みまもりネットワークへの登録が必要です。申し込みや相談は、各地域にある高齢者みまもりステーション、または高齢者福祉課へお問い合わせください。機器設置にあたり、鍵の預けや緊急連絡先の指定が必要となる場合があります。', '申請に必要な書類は荒川区公式ページに明記がなく、確認できませんでした。高齢者みまもりステーションまたは高齢者福祉課にお問い合わせください。', FALSE, '荒川区 福祉部 高齢者福祉課 高齢者福祉係', '03-3802-3111（内線：2677）', 'https://www.city.arakawa.tokyo.jp/a028/koureishairyou/shien/shien.html', 'https://www.city.arakawa.tokyo.jp/a028/koureishairyou/shien/shien.html', 'みまもりネットワークサービス（緊急通報システム）／荒川区公式サイト', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable']::text[], '本情報は荒川区公式サイト（2026-06-26時点）に基づく概要です。対象要件・利用料・機器の種別（ペンダント型の有無など）・申請手続きは変更される場合があり、また個別の状況により取り扱いが異なることがあります。申請の可否や詳細は必ず荒川区の窓口で確認してください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
