insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-arakawa-emergency-alert","status":"published","title":"緊急通報システム（みまもりネットワークサービス）","officialUrl":"https://www.city.arakawa.tokyo.jp/a028/koureishairyou/shien/shien.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-arakawa-emergency-alert:dG9reW8tYXJha2F3YS1lbWVyZ2VuY3ktYWxlcnR8' from public.support_programs sp where sp.slug='tokyo-arakawa-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'itabashi'), 'tokyo-itabashi-emergency-alert', '板橋区高齢者緊急通報システム', 'ひとり暮らしの高齢者などの自宅に緊急通報装置（通報機・ペンダント）やセンサーを設置し、急病や事故のときに緊急ボタンを押す、またはセンサーが異常を感知すると、24時間対応のコールセンターへ通報が入る板橋区の事業です。状況に応じて現場派遣員の出動、119番通報、緊急連絡先への連絡を行い、ひとり暮らし等の高齢者の安全・安心を支えます。固定電話型と固定電話不要型（携帯電話のみの方向け）が選べます。対象や利用料は公式ページでご確認ください。', 'ひとり暮らしの高齢者などの家に、ボタンを押すと助けを呼べる装置やペンダント、センサーをつける板橋区のサービスです。急に具合が悪くなったときにボタンを押すと、24時間対応のセンターにつながり、安否確認や救急車の手配などをしてくれます。利用料は世帯の状況によって変わり、生活保護世帯などは無料です。', 'service', '板橋区内にお住まいで、おおむね65歳以上のひとりぐらし世帯・高齢者のみの世帯・日中独居世帯（同居者が一定時間就労している世帯）などが対象となる可能性があります。対象年齢や要件は公式ページでご確認ください。', '機器（通報機・ペンダント等）の貸与・設置による緊急通報・安否確認サービス。利用料は公式によると、住民税非課税世帯は月額400円、住民税課税世帯は月額1,400円、生活保護世帯および中国残留邦人等支援給付世帯は無料とされています（金額・区分は変わる可能性があるため公式でご確認ください）。', '公式によると、申請には年度ごとの受付期限が設けられている場合があります（例：令和7年度設置分の申請は令和8年2月28日をもって受付終了と案内されていました）。次年度以降の受付期間や最新の締切は公式ページでご確認ください。', '公式によると、窓口（高齢政策課・おとしより相談センター）、郵送、電子申請のいずれかで申請できます（電子申請は令和7年4月1日開始）。必要書類は課税（非課税）証明書、生活保護受給証明書、就労証明書、機器設置承諾書（該当者のみ）などとされています。詳細・最新の手続きは公式ページでご確認ください。', '公式によると、課税（非課税）証明書、生活保護受給証明書、就労証明書、機器設置承諾書（該当者のみ）など。状況により異なる場合があるため公式でご確認ください。', TRUE, '板橋区 健康生きがい部 高齢政策課 高齢者相談・給付係', '03-3579-2464', 'https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1003556.html', 'https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1003556.html', '板橋区高齢者緊急通報システム｜板橋区公式ホームページ', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本ページは板橋区の公式情報をもとに整理した参考情報です。対象者・利用料・必要書類・機器の種類・申請期限などは変更される場合があります。申請の可否や詳細は必ず板橋区の公式ページ・担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
