insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nerima'), 'tokyo-nerima-emergency-alert', '緊急通報システム（高齢者在宅生活あんしん事業）', '練馬区にお住まいのひとり暮らし高齢者や高齢者のみ世帯等で、慢性疾患等により日常生活で常時注意を要する方などを対象に、自宅に緊急通報装置（付属ペンダント付き）を貸与する区独自事業です。「高齢者在宅生活あんしん事業」の一機能として位置づけられ、急病や事故などの緊急時に通報機のボタンを押すと、警備員の駆けつけと救急車の要請が行われます。室温・湿度が一定基準を超えた際に音声で注意喚起する機能もあります。対象要件・年齢・利用料・機器の種別は変わる可能性があるため、最新の内容は公式ページや地域包括支援センターでご確認ください。', 'ひとり暮らしや高齢者だけの世帯で、持病などにより見守りが必要な高齢者の自宅に、緊急通報装置とペンダントを貸し出す練馬区の事業です。急な体調不良や事故のときにボタンを押すと、警備員が駆けつけ、救急車の手配もしてもらえます。お申し込みは地域包括支援センターへ。', 'service', '練馬区に住所を有する65歳以上の方で、慢性疾患等があるなど日常生活で常時注意を要する方、介護保険の要支援・要介護認定を受けている方、または健康長寿チェックシート対象者のうち、ひとり暮らし高齢者・高齢者のみ世帯・日中または夜間に独居状態の高齢者・同居者全員が要介護等の世帯に属する高齢者のいずれかに該当する方が対象となる可能性があります（詳細は公式で確認）。', '機器は貸与で、利用料は住民税課税世帯が月額400円、非課税世帯が月額300円、生活保護世帯は無料と公式ページに記載されています（金額は変更される可能性があるため最新情報は公式でご確認ください）。', NULL, 'お住まいの地域を担当する地域包括支援センターへ申請します。詳細や申請方法は練馬区高齢者支援課 高齢給付係（電話：03-5984-2774）または地域包括支援センターにご確認ください。', NULL, FALSE, '練馬区 高齢者支援課 高齢給付係', '03-5984-2774', 'https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/hitori/zaitakuseikatusien.html', 'https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/hitori/zaitakuseikatusien.html', '高齢者在宅生活あんしん事業：練馬区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable', 'targetPeople']::text[], '対象要件・利用料・機器の種別・申請の詳細は変更される場合があります。最新かつ正確な情報は練馬区公式ページおよび地域包括支援センター・高齢者支援課でご確認ください。本サイトは情報提供のみを行うもので、受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
