insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-nerima-emergency-alert","status":"published","title":"緊急通報システム（高齢者在宅生活あんしん事業）","officialUrl":"https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/hitori/zaitakuseikatusien.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-nerima-emergency-alert:dG9reW8tbmVyaW1hLWVtZXJnZW5jeS1hbGVydHzn' from public.support_programs sp where sp.slug='tokyo-nerima-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'adachi'), 'tokyo-adachi-emergency-alert', '高齢者緊急通報システム（足立区）', '足立区が、原則ひとり暮らしまたは高齢者のみの世帯で、慢性疾患などにより日常生活上常時注意を要する高齢者の自宅に、ペンダント型ボタン等の緊急通報装置を設置・貸与し、急病や事故などの緊急時にボタン操作で通報すると、区の委託事業者が対応（必要に応じた駆けつけ・関係先への連絡等）する見守り・緊急対応事業です。利用には地域包括支援センター等による調査・認定があり、調査の結果対象とならない場合もあります。なお、足立区にはセンサー等を用いた『高齢者見守りサービス助成』など関連する別のサービスもあります。対象・利用料・機器の詳細は足立区の公式情報でご確認ください。', 'ひとり暮らしなどで持病があり健康に不安のある高齢者の家に、ボタンを押すと連絡できるペンダント型の通報装置を取り付け、急病など緊急のときに区の委託業者が対応してくれる仕組みです。利用できるかどうかは調査のうえ決まります。見守り用のセンサーなどは別のサービスとして用意されています。詳しくは足立区にお問い合わせください。', 'service', '65歳以上で在宅、原則としてひとり暮らしまたは高齢者のみの世帯の方で、慢性疾患があるなど日常生活を送るうえで常時注意を要する状態にある方が対象とされています。利用には地域包括支援センター職員等による調査・認定があり、調査の結果対象とならない場合（介護保険施設入所中、他の見守りサービス契約済み、住民票上の住所に居住していない等）もあります。具体的な対象要件は足立区の公式情報でご確認ください。', 'ペンダント型ボタン等の緊急通報装置の設置・貸与による緊急通報・対応サービスの提供。足立区の公式情報では利用者負担はありませんと案内されています（令和5年度より所得に関わらず自己負担なし）。利用料や機器の取り扱いは変わる可能性があるため、最新の条件は公式でご確認ください。', '随時受付と案内されていますが、詳細は足立区の公式情報でご確認ください。', '申し込みにあたっては、お住まいの住所を管轄する地域包括支援センター、足立区高齢福祉課在宅支援係、または足立福祉事務所各課の総合相談窓口へご相談ください。窓口に来られない方には申請書類を持って自宅訪問する対応もあると案内されています。利用には調査・認定があり、認定された方の自宅に委託業者が機器の取り付けに伺います。申請の詳しい手順・必要書類は公式でご確認ください。', '必要書類は足立区の公式情報・窓口でご確認ください。', FALSE, '足立区 高齢者地域包括ケア推進課（高齢福祉課）在宅支援係', '03-3880-5257', NULL, 'https://www.city.adachi.tokyo.jp/k-fukushi/kaigohokengai.html', '高齢者サービスのご案内（介護保険外高齢者サービス）｜足立区', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは足立区の公式情報をもとにした概要です。対象要件・利用料・機器の種類・申請手順は変更される場合があり、緊急通報システムと見守りサービス助成は別の制度です。利用にあたっては必ず足立区の公式情報および担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
