insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-adachi-emergency-alert","status":"published","title":"高齢者緊急通報システム（足立区）","officialUrl":"https://www.city.adachi.tokyo.jp/k-fukushi/kaigohokengai.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-adachi-emergency-alert:dG9reW8tYWRhY2hpLWVtZXJnZW5jeS1hbGVydHzp' from public.support_programs sp where sp.slug='tokyo-adachi-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'katsushika'), 'tokyo-katsushika-emergency-alert', '葛飾区 見守り型緊急通報システムの設置', '葛飾区が、ひとり暮らし等の高齢者の自宅に緊急通報機・各種感知器を設置し、急病や事故などの緊急時に区契約の警備会社へ通報、電話での安否確認や警備員の駆けつけにより見守る区独自の事業です。', 'ひとり暮らしなどの高齢者の家に、緊急ボタンや火災・ガス漏れ・生活異常を知らせる機器を取り付け、急に具合が悪くなったときなどに警備会社へ通報され、安否確認や駆けつけをしてもらえる葛飾区のサービスです。', 'service', '公式サイトの記載によると、65歳以上の高齢者で、身体上慢性疾患があるなど日常生活を営む上で常時注意を必要とする状態の、ひとり暮らし・高齢者のみの世帯・日中夜間に高齢者のみになる世帯の方が対象となる可能性があります。対象要件の詳細は公式で確認してください。', '自宅に専用通報機・無線通報機・火災感知器(台所)・ガス漏れ感知器(台所)・日常生活異常感知器を設置し、緊急時の通報・安否確認・駆けつけ等の見守りサービスを受けられる可能性があります。公式当該ページによると利用料金は月額370円(口座引落)と記載されていますが、金額や負担条件は変更される場合があるため、利用前に必ず公式でご確認ください。', NULL, '高齢者総合相談センター、または葛飾区高齢者支援課在宅サービス係(電話03-5654-8299)に相談する形で申請します。利用には電話の保有、家族・友人等を緊急連絡先として指定すること、玄関の鍵2組の用意、賃貸住宅の場合は住宅所有者の承諾などが必要とされています。詳細・最新の手続きは公式でご確認ください。', '電話の保有、家族・友人等の緊急連絡先、玄関の鍵2組、賃貸住宅の場合は住宅所有者の承諾などが必要とされていますが、正式な提出書類は公式で確認してください。', FALSE, '葛飾区 福祉部 高齢者支援課 在宅サービス係', '03-5654-8299', NULL, 'https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002141/1002166.html', '見守り型緊急通報システムの設置｜葛飾区公式サイト', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable', 'categorySlugs', 'lifeEventSlugs']::text[], '本情報は公式サイトを基にした概要です。対象要件・利用料金・必要書類・申請手続きは変更される場合があるため、利用にあたっては必ず葛飾区の公式ページまたは担当課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
