insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot emergency-alert import', '{"slug":"tokyo-katsushika-emergency-alert","status":"published","title":"葛飾区 見守り型緊急通報システムの設置","officialUrl":"https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002141/1002166.html","topic":"emergency-alert"}'::jsonb, 'pilot:tokyo-katsushika-emergency-alert:dG9reW8ta2F0c3VzaGlrYS1lbWVyZ2VuY3ktYWxl' from public.support_programs sp where sp.slug='tokyo-katsushika-emergency-alert' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'edogawa'), 'tokyo-edogawa-emergency-alert', '民間緊急通報システム「マモルくん」（江戸川区）', '江戸川区が実施する民間緊急通報システム「マモルくん」です。ひとり暮らしの高齢者等や一定の障害がある方の自宅に、緊急通報ボタン・火災感知器・生活リズムセンサー等を設置します。急病や火災などの際にボタンを押すと24時間受付の受信センターへ通報され、救急訓練を受けた警備員が駆けつけ、必要に応じて救急車の手配を行います。月1回の安否確認や24時間の生活相談も受けられる見守り事業です。利用料は月額2,200円で、世帯の状況により区からの助成がある場合があります。対象や利用料・助成条件は区分により異なるため、公式ページでご確認ください。', 'ひとり暮らしの高齢者や障害のある方の家に、緊急通報ボタンや火災感知器、見守りセンサーを設置する区のサービスです。急に具合が悪くなったときや火事のときにボタンを押すと、24時間受付のセンターに連絡が入り、訓練を受けた警備員が駆けつけてくれます。必要なら救急車も手配します。月1回の安否確認や、24時間の生活相談も利用できます。利用料は月2,200円で、世帯の状況により区から助成がある場合があります。', 'service', '対象となる可能性があるのは、熟年者向けでは江戸川区内の65歳以上のひとり暮らし・熟年世帯・65歳以上の方がいる世帯で希望される方です。障害者向けでは、区に住民票のある65歳未満で身体障害者手帳および愛の手帳の交付を受けている方が対象となる可能性があります。具体的な対象要件は公式ページで確認してください。', '利用料は月額2,200円（区の契約料金）。世帯の状況により区からの助成がある場合があります（詳細は公式で確認）。', '公式ページに明確な申請期限の記載は確認できませんでした（随時受付と思われます。詳細は公式で確認してください）。', '申請方法は、マイナポータルの「ぴったりサービス」による電子申請、郵送申請、窓口申請があります（熟年者向け）。障害者向けも「ぴったりサービス」での電子申請に対応しています。詳しい手続きは公式ページまたは担当窓口で確認してください。', '申請には利用申請書等が必要です。詳しい必要書類は公式ページの申請書・パンフレットまたは担当窓口で確認してください。', TRUE, '江戸川区 福祉部福祉推進課孝行係（熟年者向け）／福祉部障害者福祉課自立援助係（障害者向け）', '03-3652-1151（江戸川区代表／熟年者向け）、03-5662-0062（障害者福祉課自立援助係）', 'https://www.city.edogawa.tokyo.jp/e039/kenko/fukushikaigo/jukunen/kurashi/network.html', 'https://www.city.edogawa.tokyo.jp/e039/kenko/fukushikaigo/jukunen/kurashi/network.html', '地域支援ネットワーク（民間緊急通報システム「マモルくん」（熟年者）・目配り訪問ほか） 江戸川区ホームページ', '2026-06-24', 'high', ARRAY['対象年齢・要件（熟年者/障害者で異なる）', '利用料・助成の具体条件', '機器の種類・組み合わせ', '申請期限', '必要書類の詳細']::text[], '本情報は2026年6月26日時点で江戸川区公式サイトを確認して作成したものです。対象・利用料・助成条件・申請方法は変更される場合があります。最新かつ正確な情報は必ず公式ページおよび担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
