insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chiyoda.lg.jp/koho/kenko/koresha/sasaeai/tsuho.html', '検証実施（2026-06-26）。officialUrl到達確認・現行（更新日2026-06-01・受付終了記載なし）。許可ホスト合致（www.city.chiyoda.lg.jp）。当該区の緊急通報/見守り事業本体で、国/都の一般説明の誤認なし。一次情報原文を確認のうえ一次調査のprogramが妥当と判断し是正不要。高齢者向け『救急通報システム』と障害者向け『緊急通報システム』の2制度を1件統合している点をissuesに明記（同一事業類型・区別記載・非断定のため許容）。障害者向けページはWebFetchで404だが公式サイト内検索で現存を再確認、本文は検索スニペット由来のため一部不確実。非断定・概括+『公式で確認』を全フィールドで遵守。coverage=found・ok=true。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chiyoda' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chuo.lg.jp/a0028/kenkouiryou/koureikaigo/zaitakuiryou/zaitakushienservice/koreisyasetai/kinkyu.html', 'WebFetchで中央区公式(www.city.chuo.lg.jp／許可ホスト.lg.jp・city.*)の「緊急通報システム」ページを検証(2026-06-26)。掲載日2026-06-24で現行・受付終了の記載なし。中央区独自の緊急通報/見守り機器設置事業そのものの当該区ページであることを確認。officialUrlは高齢者向けページで、フェッチ内容と一次調査のprogram記載が完全一致——制度名「緊急通報システム」、対象=65歳以上ひとり暮らし/高齢者のみ世帯等、利用料(固定電話回線型式:課税600円/非課税無料、無線型式:課税900円/非課税450円、生活保護等無料、火災・見守りセンサー課税50円/非課税無料)、機器=緊急ペンダント・火災センサー・見守りセンサー、窓口=区役所4階高齢者福祉課またはおとしより相談センター(郵送可)、問い合わせ=高齢者福祉課高齢者サービス係 03-3546-5355。国/都制度の誤認なし、区差のある対象/利用料/機器は概括+「公式で確認」と非断定で適切に処理。障害者向け版の利用料・要件はフェッチ対象(高齢者ページ)では直接確認できないが、pro' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chuo' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.minato.tokyo.jp/zaitakushien/kenko/fukushi/koresha/sekatsu/kinkyutsuho.html', '検証完了（確認日2026-06-26）。officialUrlをWebFetchで取得し全項目を一次照合。許可ホスト一致・当該区の緊急通報/見守り事業・現行・非断定で問題なし。ok=true。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='minato' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shinjuku.lg.jp/fukushi/file05_02_00018.html', '検証完了（確認日2026-06-26）。program.officialUrl をWebFetchで取得し、一次調査の妥当性を確認した。(a)到達: 200で到達可能。(b)許可ホスト: www.city.shinjuku.lg.jp は .lg.jp かつ city.* で公式許可ホスト一致（FAQ専用ドメインではない）。(c)当該区事業: 新宿区福祉部高齢者支援課が運営する「高齢者緊急通報システム」の当該区ページであることを確認。本体機器・ペンダント・開閉センサー（希望者）・住宅用火災警報器を設置し、ボタン押下やセンサー無反応で警備会社が確認電話→不通時は救急車等が出動する区独自の緊急通報/見守り事業。(d)現行: 最終更新2026-04-01、令和8年度新規設置者の費用が記載され、受付終了の表示なし＝現行。(e)誤認なし: 国/都制度の一般説明ではなく区独自サービス。(f)対象の一部を全体と書いていない: 対象（65歳以上・一人暮らし等・慢性疾患等で常時注意を要する方・シルバーピア等未入居）を概括しuncertainFieldsに記載。(g)混在なし: 別事業の「身体障害者・難病' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinjuku' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
