insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.sumida.lg.jp/kenko_fukushi/koureisya_kaigohoken/hitorigurasi/mansei_sikkan.html', '敵対的検証完了（2026-06-26）。program.officialUrl をWebFetchで取得し到達確認。ホスト www.city.sumida.lg.jp は許可ホスト（.lg.jp／city.*）に一致。当該ページは墨田区の独自事業「救急通報システム・火災安全システム（旧・緊急通報システム）」を扱う高齢者向け区ページで、緊急通報/見守り機器設置事業そのもの。更新日2025-05-01・同日から携帯電話利用者も対象追加で現行（古い年度／受付終了でない）。対象=区内在住65歳以上のひとり暮らし又は65歳以上のみ世帯、固定電話又は携帯電話利用が条件、原則自宅の鍵の複製を預ける運用——公式記載と一次調査が一致。利用料は固定電話型式 月額0/500/2,618円、無線型式 月額0/1,100/3,718円、安否確認センサ 月額1,000円——いずれも公式の例示金額と一致しており、一次調査は概括＋「公式で確認」で適切に留保。国/都制度の誤認なし、複数制度の混在なし（救急通報＋火災安全＋安否確認センサは同一の区サービス群として扱われる）、FORBIDDEN断定なし。問い合わせ=高齢者福' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='sumida' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.koto.lg.jp/211102/fukushi/koresha/service/jisshi/6592.html', '江東区公式サイト（city.koto.lg.jp＝.lg.jp許可ホスト）の「高齢者救急通報システムの設置」ページをWebFetchで検証（更新日2024-04-01・現行）。ページは高齢者向けの緊急通報/見守り機器設置事業のみを扱い、(1)対象＝65歳以上のひとり暮らし・高齢者のみ世帯または日中長時間ひとりになる方で、慢性疾患があるなど日常生活上常時注意を要する状態かつ連絡手段がある方、(2)設置機器＝主装置・通報用ペンダント・火災/ガス/生活リズムセンサー、(3)利用者負担＝月額1,500円（非課税750円・生活保護等免除）、(4)申請＝区内21か所の長寿サポートセンターまたは長寿応援課シニア活躍支援係（本庁舎3階8番・03-3647-9468）、申請から設置まで1〜2か月、と本文に明記。これらはすべて公式本文で確認できたためtargetPeople/benefitAmountTextをuncertainから外した。一方、一次調査がdisability系スラッグと『重度身体障害者等救急通報システム』をtargetPeopleに混在させていた点は、当該ページが障害者制度を別ページへの' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='koto' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-koureisya/kenkou-koureisya-anshinkurashi/hpg000008061.html', '敵対的検証完了(2026-06-26)。品川区公式サイト(www.city.shinagawa.tokyo.jp、許可ホスト city.*/.tokyo.jp に一致、FAQ専用ドメインでない)の「品川区高齢者救急代理通報システム」ページをWebFetchで取得・照合。(a)到達OK。(b)許可ホスト一致。(c)当該区の緊急通報/見守り機器設置事業そのもの(救急ペンダントの通報ボタン+室内の生活リズムセンサー・火災センサーで警備会社に通報・駆けつけ)を確認。(d)更新日「令和8年4月1日(2026-04-01)」=現行、受付終了でない。(e)国/都制度の誤認なし=品川区独自事業。(f)対象「区内に住所がある65歳以上のひとり暮らしまたは高齢者のみの世帯、日中や夜間に独りになる高齢者世帯の方」を公式文言どおり概括。(g)別制度「障害者救急代理通報システム」とは混同せず本件は高齢者向け1件に限定済み。(h)利用料「月々のご利用料金はかかりません」を断定せず概括+公式確認の注記あり。必要書類は申請書(Word)・機器設置チェックシート(PDF)・変更届(Word)を公式で確認(初回申請は申請' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinagawa' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
