insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/kinkyutsuho.html', '検証完了（2026-06-26）。program.officialUrl（https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/kourei/hokenhukushi/kinkyutsuho.html）をWebFetchで2回取得し本文を確認。(a)到達=可（更新日2026-04-01の現行ページ、受付終了・古い年度の記載なし）。(b)許可ホスト=www.city.tokyo-nakano.lg.jp は .lg.jp/city.* に合致しPASS。(c)当該区ページ=中野区独自の「緊急通報システム」（見守り機器設置事業）そのもの。(d)現行=PASS。(e)国/都制度の誤認なし=区独自事業。(f)対象の一部を全体と書く誤りなし=高齢者・重度身体障害者の両対象を概括。(g)複数制度の混在なし=単一事業。(h)断定なし・区差項目（料金/対象/機器）は概括+「公式で確認」=PASS。料金区分を精査：公式は4区分（区分1=慢性疾患あり＋ひとり暮らし/高齢者のみ世帯:課税600/非課税300、区分2=慢性疾患なし＋同:課税1,300/非課税650' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='nakano' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.suginami.tokyo.jp/guide/koureisha/enjo/1004638.html', 'WebFetchでprogram.officialUrl（https://www.city.suginami.tokyo.jp/guide/koureisha/enjo/1004638.html）に到達。検証結果:(a)到達=OK。(b)ホスト=www.city.suginami.tokyo.jp は杉並区公式の許可ホスト（city.*かつ.tokyo.jp）。(c)当該区ページ=杉並区独自の「高齢者緊急通報システム」（ペンダント型救急ボタン・赤外線安心センサー〔無動作時自動通報〕・火災センサー〔煙感知で自動通報〕・通報機を貸与/設置し、受信センター経由で救急車/消防車要請につなぐ見守り/緊急通報事業）で一致。(d)最終更新2026-04-01・受付終了や古い年度の表示なし=現行。(e)国/都制度の一般説明ではなく杉並区の事業=誤認なし。(f)対象は「65歳以上の高齢者のみ世帯で、慢性疾患があるなど常時注意を要する方」で一次調査の記載と一致（過小/過大の歪曲なし）。WebFetchで利用不可条件〔固定/携帯電話がない・鍵を預けられない・認知症のある方など〕も確認したが、これは補足であり' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='suginami' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.toshima.lg.jp/379/kenko/koresha/ippansesaku/1502171054.html', '敵対的検証完了（2026-06-26）。program.officialUrl をWebFetchで再取得し一次調査の全主張を照合。(a)到達OK。(b)許可ホスト一致＝www.city.toshima.lg.jp（.lg.jp＋city.*）。(c)豊島区独自の緊急通報/見守り事業「高齢者救急通報システム」の当該区ページで、ペンダント型発信機・空間センサー・温湿度センサー（実証実験対象者）を貸与、ボタン押下で民間受信センターへ通報→救急要請・緊急連絡先連絡・現場派遣員駆けつけ、24時間365日健康相談、火災通報サービスも対応、と原文記載を確認。(d)更新日2026-04-02で現行、受付終了の記載なし。(e)国・都の一般説明ではなく豊島区独自事業。(f)対象要件（65歳以上の一人暮らし／高齢者のみ世帯／日中独居のいずれか＋自宅合鍵を事業者に預けられる方）を一部を全体とせず正確に記述。(g)別事業「重度障害者等緊急通報システム」（18歳以上65歳未満・障害福祉課）と混同せず、本programは高齢者向け（nursing-care）のみで登録、という一次調査の分離判断は妥当と確認。(h)' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='toshima' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.kita.lg.jp/socialcare-health/elderly/1008607/1008611.html', 'WebFetchで program.officialUrl を再取得し検証（2026-06-26）。(a)到達OK (b)許可ホスト www.city.kita.lg.jp（.lg.jp/city.*）OK (c)北区公式「高齢者見守り・緊急通報システム」当該ページOK (d)更新日2026-04-01・令和8年度対応で現行OK (e)区独自事業 (f)対象の誤記なし (g)複数制度混在なし（重度身体障害者緊急通報システムは別事業として正しく除外）(h)非断定・区差ある項目は概括＋公式確認付記。公式で確認した事実：対象＝区内在住65歳以上の一人ぐらし／高齢者のみ世帯で近隣に親族なし＋慢性疾患等で常時注意を要する方。看護師等24時間対応・緊急時119番通報・月1回安否確認電話。機器＝緊急通報装置・火災安全システム・安否確認センサ貸与、令和8年度から携帯電話対応新機器。利用料（令和8年度課税世帯）固定電話310円/機器内蔵回線410円/火災安全システム37円/安否確認センサ55円（各月額）、非課税・生活保護世帯無料。申請＝最寄りの高齢者あんしんセンター。お薬手帳等必要な場合あり。問い合わせ' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='kita' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.arakawa.tokyo.jp/a028/koureishairyou/shien/shien.html', 'WebFetchで program.officialUrl (https://www.city.arakawa.tokyo.jp/a028/koureishairyou/shien/shien.html) を実地検証(2026-06-26)。(a)到達OK (b)ホスト city.arakawa.tokyo.jp=荒川区公式の許可ホスト (c)荒川区所管「みまもりネットワークサービス」内「緊急通報システム」=区独自の緊急通報/見守り機器設置事業そのもの (d)更新日2026-05-07・受付終了/旧年度表記なし=現行 (e)国/都の一般説明ではなく区事業 (f)対象「65歳以上で1・2・3のいずれかに該当し日常生活に不安を感じる方」を一次調査が概括+非断定で記載=対象の一部を全体と誤記していない (g)複数制度の混同なし。なお重度身体障がい者向けの別事業「緊急通報サービス」(障害者福祉課・東京消防庁通報)は一次調査がtargetPeople/disclaimerNoteで「別事業」と明示しつつcategorySlugs/lifeEventSlugsにdisabilityを併記=主たる高' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='arakawa' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1003556.html', '敵対的検証完了。program.officialUrl（https://www.city.itabashi.tokyo.jp/kenko/kourei/josei/1003556.html）をWebFetchで再取得し、一次調査の主張を全て突合した。(a)到達=OK。(b)許可ホスト=www.city.itabashi.tokyo.jp はcity.*かつ.tokyo.jpの両条件を満たす公式区ドメイン、FAQ専用ドメインではない=OK。(c)当該区の緊急通報/見守り事業=ページタイトル「板橋区高齢者緊急通報システム」、通報機/ペンダント/センサーによる緊急通報・24時間コールセンター対応の板橋区独自事業で合致=OK。(d)現行性=最終更新2026-05-26で現行。ただし「令和7年度設置分の申請は令和8年（2026）2月28日をもって受付終了」と明記。これは年度ごとの申請期限であり制度の廃止ではない（次年度受付見込み）が、利用者の誤解を避けるためapplicationDeadlineTextに年度期限の注意を追記し、本文も非断定のまま維持した。(e)国/都制度の誤認なし=区独自事業=' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='itabashi' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/hitori/zaitakuseikatusien.html', '敵対的検証完了（2026-06-26）。program.officialUrl（https://www.city.nerima.tokyo.jp/hokenfukushi/koreisha/hitori/zaitakuseikatusien.html）をWebFetchで再取得し一次調査を全項目照合。(a)到達OK。(b)ホスト www.city.nerima.tokyo.jp は city.* かつ .tokyo.jp で許可ホスト一致（FAQ専用ドメインではない）。(c)練馬区公式の「高齢者在宅生活あんしん事業」ページで、緊急通報システム（通報機ボタンで警備員駆けつけ＋救急車要請、室温・湿度が一定基準超過時の音声注意喚起）の当該区事業そのものを確認。(d)更新日2026年4月1日・受付終了記載なし＝現行。(e)区独自事業であり国/都制度の一般説明ではない。(f)対象は「練馬区在住の65歳以上で慢性疾患等により常時注意を要する者、要支援・要介護等」をひとり暮らし/高齢者のみ世帯/日中・夜間独居等の枠組みで概括し、断定回避表現で一部を全体と誤記していない。(g)緊急通報システムを在宅生' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='nerima' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.adachi.tokyo.jp/k-fukushi/kaigohokengai.html', 'officialUrl(senior/torikumi/shien.html)はWebFetchで404。移動案内ページ(care-s/.../kaigohokengai.html→k-fukushi/kaigohokengai.html)を辿り現行公式ページを特定。同ページ『高齢者緊急通報システムの設置』で対象・ペンダント型ボタン貸与・申込窓口・利用者負担なしを確認。令和7年度の注記あり＝現行。生活リズムセンサー(生活活動感知器)は別制度『高齢者見守りサービス助成』に属するため本制度説明から分離して是正。連絡先03-3880-5257は複数ソース一致。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='adachi' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.katsushika.lg.jp/kenkou/1000052/1030186/1002141/1002166.html', '葛飾区公式サイト(www.city.katsushika.lg.jp、許可ホスト.lg.jp/city.*に一致)の「見守り型緊急通報システムの設置」ページ(高齢者支援課在宅サービス係)をWebFetchで直接検証。(a)到達OK (b)許可ホスト一致・FAQ専用ドメインでない (c)葛飾区独自の緊急通報/見守り機器設置事業そのものの当該区ページ (d)受付終了表示なし・更新日「令和7年4月3日」で現行 (e)国/都制度の一般説明ではなく区独自事業 (f)対象は65歳以上の特定世帯要件を正確に概括 (g)単一制度のみ (h)非断定・公式確認誘導あり。\n\n是正点: 一次調査はbenefitAmountText・summary・disclaimerNote等に『公式は月額370円だが課税状況により700円/1,750円との情報も別途あり』と非公式スニペット由来の金額を併記していた。しかし公式当該ページの実テキストを2回確認した結果、利用料金は『月額370円(口座引落)』のみで、700円/1,750円や課税区分による差額の記載は皆無。誤情報混入を避けるためbenefitAmountTex' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='katsushika' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.edogawa.tokyo.jp/e039/kenko/fukushikaigo/jukunen/kurashi/network.html', '検証完了。officialUrl（https://www.city.edogawa.tokyo.jp/e039/kenko/fukushikaigo/jukunen/kurashi/network.html）をWebFetchで取得し到達を確認。許可ホスト判定: www.city.edogawa.tokyo.jp は city.* / .tokyo.jp に一致する江戸川区公式ホスト（FAQ専用ドメインではない）。当該区の緊急通報/見守り事業そのもの＝民間緊急通報システム「マモルくん」の熟年者向け該当ページであることを確認。更新日2026-04-22で受付終了・古い年度の記載なし（現行）。記載内容を原文で照合: 対象「65歳以上のひとり暮らし、熟年世帯、65歳以上の方がいる世帯で希望される方」／機器「火災感知器や生活リズムセンサー」＋緊急通報ボタン／サービス「ボタンを押すと24時間受付の受信センターへ届き、救急訓練を受けた警備員などが駆けつけ…救急車の手配…月に1回の安否確認…生活相談も24時間」／利用料「区の契約料金（月額2,200円）…状況により区から助成」／申請「電子申請ぴったり' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='edogawa' and t.slug='emergency-alert' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
